'use client';

import { useState } from 'react';
import { 
  Settings as SettingsIcon, 
  Building, 
  Percent, 
  Lock, 
  Check, 
  ShieldCheck,
  Save
} from 'lucide-react';
import { useStore } from '@/store/useStore';

export default function SettingsPage() {
  const { user } = useStore();
  const [tab, setTab] = useState<'company' | 'security'>('company');

  // Company configs state (mocked)
  const [companyName, setCompanyName] = useState('Prime Payroll Solutions');
  const [address, setAddress] = useState('Corporate HQ, Bandra Kurla Complex, Mumbai, India');
  const [taxRate, setTaxRate] = useState('10');
  const [pfRate, setPfRate] = useState('12');
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  // Security config state
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [secSuccessMsg, setSecSuccessMsg] = useState<string | null>(null);
  const [secErrorMsg, setSecErrorMsg] = useState<string | null>(null);

  const handleSaveCompany = (e: React.FormEvent) => {
    e.preventDefault();
    setSuccessMsg(null);
    setTimeout(() => {
      setSuccessMsg('Company configuration saved successfully!');
    }, 400);
  };

  const handleSaveSecurity = (e: React.FormEvent) => {
    e.preventDefault();
    setSecSuccessMsg(null);
    setSecErrorMsg(null);

    if (newPassword !== confirmPassword) {
      setSecErrorMsg('New passwords do not match');
      return;
    }

    if (newPassword.length < 6) {
      setSecErrorMsg('Password must be at least 6 characters long');
      return;
    }

    setTimeout(() => {
      setSecSuccessMsg('Password updated successfully!');
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
    }, 400);
  };

  const isAdminOrHR = user?.role === 'ADMIN' || user?.role === 'HR';

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div>
        <h2 className="text-xl font-black text-[var(--text-primary)]">System Settings</h2>
        <p className="text-xs text-[var(--text-muted)] mt-0.5">Manage company configurations, tax parameters, and profile security</p>
      </div>

      {/* Tab selectors */}
      <div className="flex gap-4 border-b border-[var(--card-border)] pb-px">
        {isAdminOrHR && (
          <button
            onClick={() => setTab('company')}
            className={`flex items-center gap-2 py-3 text-xs font-bold border-b-2 transition-all cursor-pointer
              ${tab === 'company' 
                ? 'border-blue-600 text-blue-600' 
                : 'border-transparent text-[var(--text-secondary)] hover:text-blue-500'
              }
            `}
          >
            <Building size={14} />
            Company Config
          </button>
        )}
        <button
          onClick={() => setTab('security')}
          className={`flex items-center gap-2 py-3 text-xs font-bold border-b-2 transition-all cursor-pointer
            ${tab === 'security' || (!isAdminOrHR && tab === 'company')
              ? 'border-blue-600 text-blue-600' 
              : 'border-transparent text-[var(--text-secondary)] hover:text-blue-500'
            }
          `}
        >
          <Lock size={14} />
          Account Security
        </button>
      </div>

      {/* Tab Content */}
      <div className="max-w-2xl">
        {/* Company Settings */}
        {tab === 'company' && isAdminOrHR && (
          <div className="glass-card p-6 space-y-6 hover:transform-none">
            <div>
              <h3 className="text-sm font-bold text-[var(--text-primary)]">Company Information</h3>
              <p className="text-[10px] text-[var(--text-muted)] mt-0.5">Global configuration details used in report documents and payslips</p>
            </div>

            {successMsg && (
              <div className="p-3 text-xs font-semibold rounded-xl bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border border-emerald-200/50">
                {successMsg}
              </div>
            )}

            <form onSubmit={handleSaveCompany} className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Company Name</label>
                  <input
                    type="text"
                    required
                    value={companyName}
                    onChange={(e) => setCompanyName(e.target.value)}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Income Tax Rate (%)</label>
                  <div className="relative">
                    <Percent size={12} className="absolute right-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)]" />
                    <input
                      type="number"
                      required
                      value={taxRate}
                      onChange={(e) => setTaxRate(e.target.value)}
                      className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                    />
                  </div>
                </div>
                <div className="space-y-1 sm:col-span-2">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Registered Address</label>
                  <input
                    type="text"
                    required
                    value={address}
                    onChange={(e) => setAddress(e.target.value)}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Provident Fund (PF) Contribution (%)</label>
                  <input
                    type="number"
                    required
                    value={pfRate}
                    onChange={(e) => setPfRate(e.target.value)}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>
              </div>

              <div className="flex justify-end pt-4 border-t border-[var(--card-border)]">
                <button
                  type="submit"
                  className="flex items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 px-4 py-2.5 text-xs font-bold text-white shadow-md shadow-blue-600/10 active:scale-99 transition-all cursor-pointer"
                >
                  <Save size={14} />
                  Save Company Config
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Security Settings */}
        {(tab === 'security' || (!isAdminOrHR && tab === 'company')) && (
          <div className="glass-card p-6 space-y-6 hover:transform-none">
            <div>
              <h3 className="text-sm font-bold text-[var(--text-primary)]">Update Password</h3>
              <p className="text-[10px] text-[var(--text-muted)] mt-0.5">Ensure your account uses a secure password to prevent unauthorized access</p>
            </div>

            {secSuccessMsg && (
              <div className="p-3 text-xs font-semibold rounded-xl bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border border-emerald-200/50">
                {secSuccessMsg}
              </div>
            )}

            {secErrorMsg && (
              <div className="p-3 text-xs font-semibold rounded-xl bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border border-red-200/50">
                {secErrorMsg}
              </div>
            )}

            <form onSubmit={handleSaveSecurity} className="space-y-4">
              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Current Password</label>
                  <input
                    type="password"
                    required
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">New Password</label>
                    <input
                      type="password"
                      required
                      value={newPassword}
                      onChange={(e) => setNewPassword(e.target.value)}
                      className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Confirm New Password</label>
                    <input
                      type="password"
                      required
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                    />
                  </div>
                </div>
              </div>

              <div className="flex justify-end pt-4 border-t border-[var(--card-border)]">
                <button
                  type="submit"
                  className="flex items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 px-4 py-2.5 text-xs font-bold text-white shadow-md shadow-blue-600/10 active:scale-99 transition-all cursor-pointer"
                >
                  <Save size={14} />
                  Update Password
                </button>
              </div>
            </form>
          </div>
        )}
      </div>
    </div>
  );
}
